1	type QuoteStep = { op: "quote"; items: Array<{ type: string }> };
2	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
3	type QuoteResult = { premium: number };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	
8	const ITEM_BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	};
13	
14	const premiumForItem = (itemBase: number): number =>
15	  itemBase + Math.ceil(itemBase * FIRST_INSURANCE_RATE) + PROCESSING_FEE;
16	
17	const quoteFor = (step: QuoteStep): QuoteResult => {
18	  if (step.items.length === 0) return { premium: PROCESSING_FEE };
19	  const itemBase = ITEM_BASE_PREMIUMS[step.items[0].type];
20	  return { premium: premiumForItem(itemBase) };
21	};
22	
23	export const processScenario = (input: Scenario): { results: QuoteResult[] } => {
24	  return { results: input.steps.map(quoteFor) };
25	};
26

1	import { describe, it, expect } from "vitest";
2	import { processScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // ===== Edge cases / simplest =====
6	  it("empty item list yields premium of 5 G (only processing fee)", () => {
7	    const result = processScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // ===== Base premiums for main items (newcomer, first contract) =====
15	  it("quote for plain sword (newcomer) — premium 115 G (100 base + 10 first insurance + 5 fee)", () => {
16	    const result = processScenario({
17	      customer: { yearsWithMHPCO: 0 },
18	      steps: [{ op: "quote", items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }] }],
19	    });
20	    expect(result).toEqual({ results: [{ premium: 115 }] });
21	  });
22	  it("quote for plain amulet (newcomer) — premium 71 G (60 base + 6 first insurance + 5 fee)", () => {
23	    const result = processScenario({
24	      customer: { yearsWithMHPCO: 0 },
25	      steps: [{ op: "quote", items: [{ type: "amulet", material: "silver", enchantment: 2, cursed: false }] }],
26	    });
27	    expect(result).toEqual({ results: [{ premium: 71 }] });
28	  });
29	  it("quote for plain staff (newcomer) — premium 93 G (80 base + 8 first insurance + 5 fee)", () => {
30	    const result = processScenario({
31	      customer: { yearsWithMHPCO: 0 },
32	      steps: [{ op: "quote", items: [{ type: "staff", material: "oak", enchantment: 1, cursed: false }] }],
33	    });
34	    expect(result).toEqual({ results: [{ premium: 93 }] });
35	  });
36	  it.todo("quote for plain potion (newcomer) — premium 49 G (40 base + 4 first insurance + 5 fee)");
37	
38	  // ===== Components and building blocks =====
39	  it.todo("2 runes yield 50 G base premium (no block)");
40	  it.todo("3 runes yield 60 G base premium (block of 3 alike applies)");
41	  it.todo("4 runes yield 100 G base premium (no block — block requires exactly 3)");
42	  it.todo("7 runes yield 175 G base premium (no block formation)");
43	  it.todo("2 runes + 1 moonstone yield 75 G base premium (no block: different types)");
44	  it.todo("3 runes + 3 moonstones yield 120 G base premium (two separate blocks)");
45	
46	  // ===== Premium modifiers — thresholds and isolation =====
47	  it.todo("cursed sword adds 50% surcharge on the sword's base premium");
48	  it.todo("sword with exactly enchantment 5 triggers high-enchantment surcharge");
49	  it.todo("sword with enchantment 4 does not trigger high-enchantment surcharge");
50	  it.todo("cursed sword with exactly enchantment 5 triggers both surcharges");
51	  it.todo("customer with exactly 2 years receives 20% loyalty discount");
52	  it.todo("each item in a quote is treated as first insurance (10% surcharge applies even on follow-up contracts)");
53	
54	  // ===== Modifier scope on multi-item policies =====
55	  it.todo("cursed sword + plain amulet — base 160 G + 50 G curse = 210 G before policy modifiers and fee");
56	
57	  // ===== Rounding (MHPCO's favor) =====
58	  it.todo("premium calculation yielding 197.5 G rounds up to 198 G");
59	  it.todo("payout calculation yielding 350.5 G rounds down to 350 G");
60	
61	  // ===== Integration: newcomer with cursed sword =====
62	  it.todo("newcomer (0 years), cursed sword (steel, ench 3) — premium 165 G");
63	
64	  // ===== Integration: long-standing customer's second contract =====
65	  it.todo("3-year customer's 2nd quote, cursed sword (steel, ench 7) — premium 160 G");
66	
67	  // ===== Claim processing: standard reimbursement =====
68	  it.todo("regular sword (steel, ench 3), damage 500 G — payout 400 G (full minus deductible)");
69	  it.todo("rune damage 200 G — payout 100 G (full minus deductible, no special clause)");
70	
71	  // ===== Claim processing: special clauses =====
72	  it.todo("dragon-material sword, ench 5, damage 800 G — payout 700 G (dragon full, then deductible)");
73	  it.todo("steel sword, ench 9, damage 1000 G — payout 400 G (50% then deductible)");
74	  it.todo("dragon-material sword, ench 9, damage 1000 G — payout 400 G (50% wins, then deductible)");
75	  it.todo("dragon-material sword, exact ench 8, damage 1000 G — payout 400 G (50% applies, then deductible)");
76	
77	  // ===== Deductible per damage event =====
78	  it.todo("dragon attack damages sword (500 G) and amulet (300 G) — payout 600 G (deductible per item)");
79	
80	  // ===== Multiple items of same type =====
81	  it.todo("policy covers 2 swords — insurance sum 2000 G, cap 4000 G");
82	  it.todo("dragon attack damages both swords (two sword damages) — each with own deductible");
83	  it.todo("claim with more damage entries of a type than insured — CLI exits non-zero");
84	
85	  // ===== Cap exhaustion =====
86	  it.todo("policy with sword + amulet — insurance sum 1600 G, cap 3200 G");
87	  it.todo("cursed sword — cap stays at 2000 G (based on unmodified insurance value)");
88	  it.todo("policy with sword + 3 runes (block) — insurance sum 1750 G (block discount affects premium only)");
89	  it.todo("sword cap 2000 G, two successive 1500 G claims — payouts 1400 G then 600 G; remainingCap 600 then 0");
90	
91	  // ===== Error cases =====
92	  it.todo("quote with unknown item type — CLI exits non-zero, stderr error, no results");
93	  it.todo("claim references damage for item not in policy — CLI exits non-zero with stderr");
94	  it.todo("claim damage with negative amount — CLI exits non-zero with stderr");
95	
96	  // ===== Multi-step scenario =====
97	  it.todo("scenario: quote then claim referencing it by step index — returns both results in order");
98	});
